MAX_EMAIL_LENGTH = 50000
RATE_LIMIT_STORE = {}
RATE_LIMIT_MAX = 100
RATE_LIMIT_WINDOW = 60

MODEL_PATH = "spam_model.pkl"
VECTORIZER_PATH = "spam_vectorizer.pkl"

model = None
vectorizer = None


def require_api_key(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        provided_key = request.headers.get("X-API-Key", "")
        if not provided_key or not secrets.compare_digest(provided_key, API_KEY):
            logger.warning("Unauthorized access attempt from %s", request.remote_addr)
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated


def rate_limit(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        import time
        client_ip = request.remote_addr
        now = time.time()

        if client_ip in RATE_LIMIT_STORE:
            requests_list = RATE_LIMIT_STORE[client_ip]
            requests_list = [t for t in requests_list if now - t < RATE_LIMIT_WINDOW]
            RATE_LIMIT_STORE[client_ip] = requests_list

            if len(requests_list) >= RATE_LIMIT_MAX:
                logger.warning("Rate limit exceeded for %s", client_ip)
                return jsonify({"error": "Rate limit exceeded. Try again later."}), 429
        else:
            RATE_LIMIT_STORE[client_ip] = []

        RATE_LIMIT_STORE[client_ip].append(now)
        return f(*args, **kwargs)
    return decorated


def sanitize_text(text):
    if not isinstance(text, str):
        raise ValueError("Input must be a string")
    text = text[:MAX_EMAIL_LENGTH]
    text = text.replace("\x00", "")
    text = re.sub(r'[^\w\s@.,!?;:\-\'\"()/\\$%&#+=<>\[\]{}|~`^*]', '', text)
    return text.strip()


